examples.toCode:
#include <stdlib.h>

typedef struct {
    unsigned char* data;
    int size;
} BufferHolder;

BufferHolder* create_buffer(int size) {
    BufferHolder* b = (BufferHolder*)malloc(sizeof(BufferHolder));
    b->data = (unsigned char*)malloc(size);
    b->size = size;
    return b;
}

void free_buffer(BufferHolder* b) {
    free(b->data);
    free(b);
}

